import{M as an}from"./scene21.js";function el(){return`struct LE{d:vec4<f32>,c:vec4<f32>,s:vec4<f32>,r:vec4<f32>,};struct LU{count:u32,_p0:u32,_p1:u32,_p2:u32,lights:array<LE,${an}>,};`;}const ma="struct PLR{L:vec3<f32>,NdotL:f32,atten:f32,color:vec3<f32>,sc:vec3<f32>,ih:bool};fn cpl(e:LE,N:vec3<f32>,worldPos:vec3<f32>,lightFalloffMode:f32)->PLR{var r:PLR;let t=u32(e.d.w);r.ih=t==3u;r.sc=e.c.rgb;if(t==3u){r.L=normalize(e.d.xyz);r.NdotL=dot(N,r.L)*0.5+0.5;r.atten=1.0;r.color=mix(e.r.xyz,e.c.rgb,r.NdotL);return r;}if(t==1u){r.L=normalize(-e.d.xyz);r.atten=1.0;}else{let tl=e.d.xyz-worldPos;let d2=dot(tl,tl);let dst=sqrt(d2);r.L=tl/max(dst,0.0001);let physicalFalloff=lightFalloffMode>=0.5;let rat=select(max(0.0,1.0-dst/e.c.a),1.0/max(d2,0.0000001),physicalFalloff);if(t==2u){let cosHalfAngle=e.r.w;let c=dot(-e.r.xyz,r.L);let standardDirFalloff=select(0.0,max(0.0,pow(max(c,0.0),e.s.a)),c>=cosHalfAngle);let kappa=6.64385618977/max(1.0-cosHalfAngle,0.0001);let physicalDirFalloff=exp2(kappa*(c-1.0));r.atten=rat*select(standardDirFalloff,physicalDirFalloff,physicalFalloff);}else{r.atten=rat;}}r.NdotL=max(dot(N,r.L),0.0);r.color=e.c.rgb;return r;}";function tl(){return`var dd=vec3<f32>(0.0);var ds=vec3<f32>(0.0);let dr=max(rg,aax);let dag=dr*dr+0.0005;var sf=array<f32,${an}>(${Array(an).fill("1.0").join(", ")});let lc=min(mesh.lc,${an}u);/*AS*/let li0=mli(0u);let entry0=lights.lights[li0];let pl0=cpl(entry0,N,input.worldPos,material.lightFalloffMode);let L=pl0.L;let NdotL=pl0.NdotL;let lc=pl0.sc;let la=pl0.atten*sf[li0];let H=normalize(V+L);let NdotH=clamp(dot(N,H),0.0000001,1.0);let VdotH=saturate(dot(V,H));for(var li=0u;li<lc;li++){var pl:PLR;let lix=mli(li);if(li==0u){pl=pl0;}else{pl=cpl(lights.lights[lix],N,input.worldPos,material.lightFalloffMode);}let sf=sf[lix];if(pl.ih){dd+=pl.color*sa*material.directIntensity*sf;}else{dd+=sa*(1.0/PI)*pl.NdotL*pl.color*pl.atten*material.directIntensity*sf;}if(pl.NdotL>0.0 && pl.atten>0.0){let specH=normalize(V+pl.L);let specNdotH=clamp(dot(N,specH),0.0000001,1.0);let specVdotH=saturate(dot(V,specH));let D=distributionGGX(specNdotH,dag);let G=geometrySmithGGX(pl.NdotL,nv,dag);let cf=fresnelSchlick(specVdotH,f0,f90);ds+=cf*D*G*pl.NdotL*pl.sc*pl.atten*material.directIntensity*sf;}}/*AD*/`;}export{ma as COMPUTE_PBR_LIGHT,el as MULTI_LIGHT_STRUCTS,tl as getMultiLightLoop};